const data = $input.first().json || {};
const context = data.context || {};
const router = data.router_output || {};
const candidateProducts = Array.isArray(context.candidate_products) ? context.candidate_products : [];
const normalizedUserMessage = String(data.user_message || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const unique = (values) => [...new Set(values.filter(Boolean))];
const formatBrandLabel = (brandKey) => {
  const labels = {
    apple: 'iPhone',
    samsung: 'Samsung',
    motorola: 'Motorola',
    xiaomi: 'Xiaomi',
    redmi: 'Redmi',
    google: 'Google Pixel',
    jbl: 'JBL',
  };
  return labels[brandKey] || String(brandKey || '').trim();
};
const formatArs = (value) => {
  const amount = Number(value);
  if (!Number.isFinite(amount) || amount <= 0) return null;
  return 'ARS ' + new Intl.NumberFormat('es-AR', { maximumFractionDigits: 0 }).format(amount);
};
const publicPrice = (product) => {
  const promo = Number(product?.promo_price_ars);
  if (Number.isFinite(promo) && promo > 0) return promo;
  const price = Number(product?.price_ars);
  if (Number.isFinite(price) && price > 0) return price;
  return Number.POSITIVE_INFINITY;
};
const sortProducts = (products) =>
  [...products].sort((left, right) => {
    if (Number(right?.in_stock) !== Number(left?.in_stock)) {
      return Number(right?.in_stock) - Number(left?.in_stock);
    }
    const leftPrice = publicPrice(left);
    const rightPrice = publicPrice(right);
    if (leftPrice !== rightPrice) {
      return leftPrice - rightPrice;
    }
    return String(left?.product_name || '').localeCompare(String(right?.product_name || ''), 'es');
  });
const buildInstallmentLine = (product) => {
  const cuotasQty = Number(product?.cuotas_qty);
  if (!Number.isFinite(cuotasQty) || cuotasQty < 2) return null;
  const options = [];
  const bancarizada = formatArs(product?.bancarizada_cuota);
  const macro = formatArs(product?.macro_cuota);
  if (bancarizada) options.push(cuotasQty + ' de ' + bancarizada + ' con bancarizadas');
  if (macro) options.push(cuotasQty + ' de ' + macro + ' con Macro');
  return options.length > 0 ? 'Cuotas: ' + options.join(' o ') : null;
};
const buildProductBlock = (product) => {
  const lines = [String(product?.product_name || 'Producto')];
  const contado = formatArs(product?.promo_price_ars ?? product?.price_ars);
  if (contado) lines.push('Contado: ' + contado);
  const cuotas = buildInstallmentLine(product);
  if (cuotas) lines.push(cuotas);
  if (product?.product_url) lines.push('Link: ' + String(product.product_url).trim());
  return lines.join('\n');
};
const buildBrandSection = (brandKey, products) => {
  const lines = [formatBrandLabel(brandKey) + ':'];
  for (const product of products) {
    lines.push('', buildProductBlock(product));
  }
  return lines.join('\n');
};

const requestedBrandKeys = unique((Array.isArray(router.requested_brand_keys) ? router.requested_brand_keys : []).map((value) => String(value || '').trim().toLowerCase()));
const rankedProducts = [...candidateProducts];
const catalogProducts = sortProducts(candidateProducts);
const availableBrandKeys = unique(candidateProducts.map((product) => String(product?.brand_key || '').trim().toLowerCase()).filter(Boolean));
const brandOptions = unique(candidateProducts.map((product) => formatBrandLabel(String(product?.brand_key || '').trim().toLowerCase())).filter(Boolean)).slice(0, 6);
const catalogBrandKeys = requestedBrandKeys.length > 0 ? requestedBrandKeys : availableBrandKeys;
const mentionsPaymentIntent = /(cuota|cuotas|contado|tarjeta|macro|bancarizada|financi|pago|pagar|transferencia)/.test(normalizedUserMessage);

let replyText = '';
let actions = [];
let selectedProductKeys = [];
let stateDelta = {
  intent_key: 'greeting',
  funnel_stage: 'browsing',
  lead_score_delta: 3,
  share_store_location: false,
  selected_product_keys: [],
  tags_to_add: [],
  tags_to_remove: [],
  payment_method_key: mentionsPaymentIntent ? 'contado_cuotas' : null,
  summary: 'Turno comercial determinístico.',
};

switch (router.route_key) {
  case 'brand_catalog': {
    if (catalogBrandKeys.length === 0) {
      replyText = brandOptions.length > 0
        ? 'Decime la marca que te gusta y te mando opciones con precio de contado y cuotas.\n\nHoy estan saliendo mucho ' + brandOptions.join(', ') + '.'
        : 'Decime la marca que te gusta y te mando opciones con precio de contado y cuotas.';
      stateDelta.intent_key = 'catalog_browse';
      stateDelta.summary = 'Faltó una marca concreta para listar catálogo.';
      break;
    }

    const sections = [];
    const missingBrands = [];

    for (const brandKey of catalogBrandKeys) {
      const brandProducts = sortProducts(catalogProducts.filter((product) => String(product?.brand_key || '').trim().toLowerCase() === brandKey));
      if (brandProducts.length === 0) {
        missingBrands.push(formatBrandLabel(brandKey));
        continue;
      }
      sections.push(buildBrandSection(brandKey, brandProducts));
      selectedProductKeys.push(...brandProducts.map((product) => String(product.product_key || '')).filter(Boolean));
    }

    if (sections.length === 0) {
      replyText = 'Ahora mismo no veo publicaciones activas para esa marca. Si queres, te muestro otra y te paso opciones con contado y cuotas.';
      stateDelta.intent_key = 'catalog_browse';
      stateDelta.summary = 'Sin productos activos para las marcas pedidas.';
      break;
    }

    const intro = catalogBrandKeys.length > 1
      ? 'Te paso todo lo que tengo publicado de ' + catalogBrandKeys.map(formatBrandLabel).join(' y ') + ', con precio de contado y cuotas:'
      : 'Te paso lo que tengo publicado de ' + formatBrandLabel(catalogBrandKeys[0]) + ', con precio de contado y cuotas:';
    const outroParts = [];
    if (missingBrands.length > 0) {
      outroParts.push('De ' + missingBrands.join(' y ') + ' no veo publicaciones activas ahora mismo.');
    }
    outroParts.push('Si queres, te marco rapido cuales son las mejores opciones segun tu presupuesto.');

    replyText = [intro, ...sections, outroParts.join(' ')].join('\n\n');
    actions = ['attach_store_url'];
    selectedProductKeys = unique(selectedProductKeys);
    stateDelta.intent_key = 'catalog_browse';
    stateDelta.funnel_stage = 'browsing';
    stateDelta.lead_score_delta = catalogBrandKeys.length > 1 ? 7 : 6;
    stateDelta.summary = catalogBrandKeys.length > 1
      ? 'Catálogo determinístico para varias marcas: ' + catalogBrandKeys.map(formatBrandLabel).join(', ') + '.'
      : 'Catálogo determinístico por marca: ' + formatBrandLabel(catalogBrandKeys[0]) + '.';
    break;
  }
  case 'exact_product_quote': {
    const product = rankedProducts[0] || null;
    if (!product) {
      replyText = brandOptions.length > 0
        ? 'Decime la marca o el modelo y te paso la opcion correcta con contado y cuotas.\n\nHoy estan entrando mucho ' + brandOptions.join(', ') + '.'
        : 'Decime la marca o el modelo y te paso la opcion correcta con contado y cuotas.';
      stateDelta.intent_key = 'price_inquiry';
      stateDelta.funnel_stage = 'browsing';
      stateDelta.summary = 'No hubo producto concreto para cotizar.';
      break;
    }

    replyText =
      'Te paso una opcion concreta para cerrar rapido:\n\n' +
      buildProductBlock(product) +
      '\n\nSi queres, tambien te digo color, memoria y la mejor opcion de cuotas para avanzar con la compra.';
    actions = ['attach_store_url'];
    selectedProductKeys = [String(product.product_key || '')].filter(Boolean);
    stateDelta.intent_key = 'price_inquiry';
    stateDelta.funnel_stage = 'interested';
    stateDelta.lead_score_delta = 8;
    stateDelta.summary = 'Cotización determinística de producto puntual.';
    break;
  }
  case 'generic_sales':
  default: {
    replyText = brandOptions.length > 0
      ? 'Decime la marca o el modelo que te interesa y te paso opciones buenas con precio de contado y cuotas.\n\nHoy estan saliendo mucho ' + brandOptions.join(', ') + '.'
      : 'Decime la marca o el modelo que te interesa y te paso opciones buenas con precio de contado y cuotas.';
    stateDelta.intent_key = 'greeting';
    stateDelta.funnel_stage = 'browsing';
    stateDelta.lead_score_delta = 3;
    stateDelta.summary = 'Se pidió la marca antes de listar productos.';
    break;
  }
}

stateDelta.selected_product_keys = [...selectedProductKeys];

return [{
  json: {
    ...data,
    responder_output: {
      route_key: router.route_key || 'generic_sales',
      reply_text: replyText.trim(),
      selected_product_keys: selectedProductKeys,
      actions,
      state_delta: stateDelta,
    },
    responder_provider_name: 'deterministic',
    responder_model_name: 'deterministic-brand-sales',
    responder_raw_text: replyText.trim(),
  }
}];

const base = $input.first().json || {};
const responder = base.responder_output && typeof base.responder_output === 'object'
  ? base.responder_output
  : {
      route_key: base.router_output?.route_key || 'generic_sales',
      reply_text: 'Decime la marca o el modelo que te interesa y te paso opciones con precio de contado y cuotas.',
      selected_product_keys: [],
      actions: [],
      state_delta: {
        intent_key: 'greeting',
        funnel_stage: 'browsing',
        lead_score_delta: 3,
        share_store_location: false,
        selected_product_keys: [],
        tags_to_add: [],
        tags_to_remove: [],
        payment_method_key: null,
        summary: 'Fallback determinístico por falta de respuesta.',
      },
    };

return [{
  json: {
    ...base,
    responder_output: responder,
    responder_provider_name: 'deterministic',
    responder_model_name: 'deterministic-brand-sales',
    responder_raw_text: String(responder.reply_text || ''),
  }
}];
